import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Enrollment } from '../../core/models';

/**
 * LearnLoop "My Courses" — lists the caller's enrollments with a progress bar
 * for each. Loads via ApiService.myCourses() in ngOnInit().
 */
@Component({
  selector: 'app-my-courses',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './my-courses.component.html',
  styleUrl: './my-courses.component.css',
})
export class MyCoursesComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly enrollments = signal<Enrollment[]>([
    {
      id: 'e1',
      courseId: 'c1',
      userId: 'demo-student',
      progressPct: 40,
      course: {
        id: 'c1',
        title: 'Intro to Web Development',
        description: 'HTML, CSS, and the fundamentals of the browser.',
        lessonCount: 3,
        quizCount: 1,
      },
    },
    {
      id: 'e2',
      courseId: 'c2',
      userId: 'demo-student',
      progressPct: 75,
      course: {
        id: 'c2',
        title: 'JavaScript Foundations',
        description: 'Variables, functions, and control flow.',
        lessonCount: 8,
        quizCount: 2,
      },
    },
    {
      id: 'e3',
      courseId: 'c3',
      userId: 'demo-student',
      progressPct: 100,
      course: {
        id: 'c3',
        title: 'Design Thinking Essentials',
        description: 'Empathise, frame, and prototype.',
        lessonCount: 5,
        quizCount: 1,
      },
    },
  ]);

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.myCourses().subscribe({
      next: (enrollments) => {
        this.enrollments.set(enrollments);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load your courses. Please try again.');
        this.loading.set(false);
      },
    });
  }
}
